from flask import Flask, request
import jwt
import datetime
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = 'super-secret'  # Replace this with your own secret key

def require_appkey(view_function):
    @wraps(view_function)
    def decorated_function(*args, **kwargs):
        if request.headers.get('Authorization') and request.headers.get('Authorization').startswith("Bearer "):
            token = request.headers['Authorization'][7:]
            try:
                jwt.decode(token, app.config['SECRET_KEY'])
            except:
                return {"error": "Invalid Token"}, 403
        else:
            return {"error": "Missing Authorization Header"}, 401
        return view_function(*args, **kwargs)
    return decorated_function

@app.route('/login', methods=['POST'])
def login():
    if request.form['username'] and request.form['password']:   # validate the user input
        exp = datetime.datetime.utcnow() + datetime.timedelta(minutes=30)  # set token to expire after 30 minutes
        token = jwt.encode({'exp': exp, 'username': request.form['username']}, app.config['SECRET_KEY'], algorithm="HS256")
        return {'token': token}
    else:
        return {"error": "Invalid Request"}, 401

@app.route('/protected', methods=['GET'])
@require_appkey
def protected():
    return {"message": "Access Granted"}